+    async function renderGallery() {
+      els.galleryGrid.innerHTML = "";
+
+      for (const sample of samples) {
+        const card = document.createElement("article");
+        card.className = "rounded-[1.75rem] border border-white/10 bg-slate-950/40 p-5";
+        card.innerHTML = `
+          <div class="flex flex-col gap-4">
+            <div class="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
+              <div>
+                <div class="flex flex-wrap items-center gap-2">
+                  <h3 class="text-xl font-bold text-white">${sample.label}</h3>
+                  <span class="pill ${badgeClass(sample.description.toLowerCase().includes("implemented") ? "implemented" : "partial")} rounded-full px-3 py-1 text-[11px] font-semibold uppercase tracking-[0.18em]">${sample.description}</span>
+                </div>
+                <p class="mt-2 text-sm leading-6 text-slate-300">${sample.code.split("\n")[0]}</p>
+              </div>
+              <button
+                type="button"
+                data-gallery-sample="${sample.id}"
+                class="rounded-full border border-cobalt/30 bg-cobalt/15 px-4 py-2 text-sm font-semibold text-cobalt transition hover:bg-cobalt/25"
+              >
+                Open In Editor
+              </button>
+            </div>
+            <div class="gallery-stage scrollbar-thin overflow-auto rounded-[1.25rem] border border-white/10 bg-white p-4 text-slate-900" data-gallery-render="${sample.id}">
+              <div class="text-sm text-slate-500">Rendering ${sample.label}...</div>
+            </div>
+            <pre class="scrollbar-thin max-h-56 overflow-auto rounded-[1.25rem] border border-white/10 bg-[#08101d] p-4 text-xs leading-6 text-slate-300">${sample.code.replace(/</g, "&lt;")}</pre>
+          </div>
+        `;
+        els.galleryGrid.appendChild(card);
+      }
+
+      for (const button of els.galleryGrid.querySelectorAll("[data-gallery-sample]")) {
+        button.addEventListener("click", () => {
+          const sample = samples.find((entry) => entry.id === button.dataset.gallerySample);
+          if (!sample) {
+            return;
+          }
+          currentSample = sample;
+          els.input.value = sample.code;
+          updateActiveSample();
+          renderAll();
+          window.scrollTo({ top: els.input.getBoundingClientRect().top + window.scrollY - 96, behavior: "smooth" });
+        });
+      }
+
+      for (const sample of samples) {
+        const target = els.galleryGrid.querySelector(`[data-gallery-render="${sample.id}"]`);
+        if (!target) {
+          continue;
+        }
+
+        if (!frankenRuntime) {
+          target.innerHTML = `
+            <div class="rounded-2xl border border-amber-300/20 bg-amber-300/10 p-4 text-sm leading-6 text-amber-100">
+              frankenmermaid runtime unavailable for this gallery card.
+            </div>
+          `;
+          continue;
+        }
+
+        try {
+          const svg = await frankenRuntime.renderSvg(sample.code, { theme: "corporate" });
+          target.innerHTML = svg;
+        } catch (error) {
+          target.innerHTML = `
+            <div class="rounded-2xl border border-rose-300/20 bg-rose-300/10 p-4 text-sm leading-6 text-rose-200">
+              ${String(error)}
+            </div>
+          `;
+        }
+      }
+    }
